const AuditPage: React.FC = () => {
  const { addAudit } = useStore();
  const [step, setStep] = useState(0); // 0: intro, 1-5: pillars, 6: contact, 7: results
  const [scores, setScores] = useState<Record<string, number>>({
    strategy: 0, operations: 0, data: 0, tools: 0, people: 0
  });
  const [userInfo, setUserInfo] = useState({ name: '', email: '', company: '' });

  const totalSteps = PILLARS.length + 1; // Pillars + Contact

  const handleScoreChange = (pillarId: string, value: number) => {
    setScores(prev => ({ ...prev, [pillarId]: value }));
  };

  const nextStep = () => {
    if (step === PILLARS.length + 1) {
      // Calculate and save
      // FIX: Cast Object.values to number[] to avoid operator '+' cannot be applied to types 'unknown' and 'unknown' error
      const total = (Object.values(scores) as number[]).reduce((a, b) => a + b, 0);
      addAudit({
        ...userInfo,
        scores: scores as any,
        totalScore: total
      });
    }
    setStep(prev => prev + 1);
  };

  const renderProgress = () => {
    const progress = (step / totalSteps) * 100;
    return (
      <div className="w-full bg-zinc-900 h-1.5 rounded-full mb-12">
        <div 
          className="bg-purple-600 h-full rounded-full transition-all duration-500" 
          style={{ width: `${progress}%` }}
        />
      </div>
    );
  };

  const renderIntro = () => (
    <div className="max-w-2xl mx-auto text-center py-12">
      <h2 className="text-4xl font-bold text-white mb-6">AI Readiness Audit</h2>
      <p className="text-lg text-zinc-400 mb-12">
        This diagnostic takes 5 minutes. You will receive a high-level maturity score across 5 critical business pillars and a preview of where your biggest AI opportunities lie.
      </p>
      <button 
        onClick={() => setStep(1)}
        className="px-12 py-5 bg-purple-600 text-white font-bold rounded-2xl hover:bg-purple-700 transition-all text-xl"
      >
        Begin Diagnostic
      </button>
    </div>
  );

  const renderPillarStep = (idx: number) => {
    const pillar = PILLARS[idx - 1];
    return (
      <div className="max-w-2xl mx-auto py-12">
        <h3 className="text-sm font-bold text-purple-400 uppercase tracking-[0.2em] mb-4">Pillar 0{idx}</h3>
        <h2 className="text-4xl font-bold text-white mb-10">{pillar.label}</h2>
        <div className="space-y-12">
          {pillar.questions.map((q, qIdx) => (
            <div key={qIdx}>
              <p className="text-xl text-zinc-300 mb-6">{q}</p>
              <div className="grid grid-cols-5 gap-3">
                {[1, 2, 3, 4, 5].map((val) => (
                  <button
                    key={val}
                    onClick={() => handleScoreChange(pillar.id, val)}
                    className={`h-14 rounded-xl border-2 transition-all font-bold text-lg ${
                      scores[pillar.id] === val 
                        ? 'bg-purple-600 border-purple-600 text-white scale-105' 
                        : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:border-zinc-700'
                    }`}
                  >
                    {val}
                  </button>
                ))}
              </div>
              <div className="flex justify-between text-xs text-zinc-600 mt-3 font-semibold uppercase tracking-wider">
                <span>Not at all</span>
                <span>Fully Optimized</span>
              </div>
            </div>
          ))}
        </div>
        <div className="mt-16 flex justify-between">
           <button onClick={() => setStep(step - 1)} className="text-zinc-500 font-bold hover:text-white transition-colors">Back</button>
           <button 
             disabled={scores[pillar.id] === 0}
             onClick={nextStep} 
             className="px-8 py-4 bg-white text-black font-bold rounded-xl hover:bg-zinc-200 disabled:opacity-50 transition-all"
           >
             Continue
           </button>
        </div>
      </div>
    );
  };

  const renderContactStep = () => (
    <div className="max-w-xl mx-auto py-12 text-center">
      <h2 className="text-4xl font-bold text-white mb-6">Almost Finished</h2>
      <p className="text-zinc-400 mb-10">Where should I send your full custom AI report?</p>
      <div className="space-y-4 mb-10">
        <input 
          type="text" 
          placeholder="Your Name" 
          className="w-full bg-zinc-900 border border-zinc-800 p-4 rounded-xl text-white outline-none focus:border-purple-600 transition-colors"
          value={userInfo.name}
          onChange={e => setUserInfo({...userInfo, name: e.target.value})}
        />
        <input 
          type="email" 
          placeholder="Business Email" 
          className="w-full bg-zinc-900 border border-zinc-800 p-4 rounded-xl text-white outline-none focus:border-purple-600 transition-colors"
          value={userInfo.email}
          onChange={e => setUserInfo({...userInfo, email: e.target.value})}
        />
        <input 
          type="text" 
          placeholder="Company" 
          className="w-full bg-zinc-900 border border-zinc-800 p-4 rounded-xl text-white outline-none focus:border-purple-600 transition-colors"
          value={userInfo.company}
          onChange={e => setUserInfo({...userInfo, company: e.target.value})}
        />
      </div>
      <button 
        disabled={!userInfo.name || !userInfo.email}
        onClick={nextStep}
        className="w-full py-5 bg-purple-600 text-white font-bold rounded-2xl hover:bg-purple-700 transition-all text-xl"
      >
        Generate My Results
      </button>
    </div>
  );

  const renderResults = () => {
    // FIX: Cast Object.values to number[] to avoid operator '+' cannot be applied to types 'unknown' and 'unknown' error
    const avg = (Object.values(scores) as number[]).reduce((a, b) => a + b, 0) / 5;
    const level = Math.ceil(avg);
    const insights = [
      { pillar: 'Strategy', status: scores.strategy > 3 ? 'Strong' : 'At Risk' },
      { pillar: 'Operations', status: scores.operations > 3 ? 'Strong' : 'Inefficient' },
      { pillar: 'Data', status: scores.data > 3 ? 'Strong' : 'Gaps Detected' },
    ];

    return (
      <div className="max-w-4xl mx-auto py-12">
        <div className="text-center mb-16">
          <h2 className="text-2xl font-bold text-zinc-500 mb-4">Your AI Maturity Level</h2>
          <div className="text-9xl font-black text-white mb-6">
            {avg.toFixed(1)}<span className="text-purple-600 text-5xl">/5</span>
          </div>
          <p className="text-2xl text-white font-bold">
            {level <= 2 ? 'Stage 1: AI Observer' : level <= 4 ? 'Stage 3: AI Practitioner' : 'Stage 5: AI Strategic Leader'}
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-16">
          {insights.map((insight, i) => (
            <div key={i} className="bg-zinc-900 p-8 rounded-3xl border border-zinc-800">
               <h4 className="text-zinc-500 text-sm font-bold uppercase mb-2">{insight.pillar}</h4>
               <p className={`text-xl font-bold ${insight.status === 'Strong' ? 'text-emerald-400' : 'text-amber-400'}`}>
                 {insight.status}
               </p>
            </div>
          ))}
        </div>

        <div className="bg-purple-600 rounded-[3rem] p-12 text-center text-white">
          <h3 className="text-3xl font-bold mb-6">Receive Your Comprehensive PDF Audit</h3>
          <p className="text-lg text-purple-100 mb-10 max-w-2xl mx-auto">
            I've processed your data. My team will now review your scores and send a detailed 15-page gap analysis and strategic roadmap within 24 hours.
          </p>
          <a href="#home" className="inline-block px-12 py-5 bg-white text-black font-bold rounded-2xl hover:bg-zinc-100 transition-all text-lg">
            Return to Homepage
          </a>
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] pt-12 px-6">
      <div className="max-w-5xl mx-auto">
        {step > 0 && step <= PILLARS.length + 1 && renderProgress()}
        {step === 0 && renderIntro()}
        {step >= 1 && step <= PILLARS.length && renderPillarStep(step)}
        {step === PILLARS.length + 1 && renderContactStep()}
        {step === PILLARS.length + 2 && renderResults()}
      </div>
    </div>
  );
};

