      <div className="max-w-3xl mx-auto py-12 animate-fade-up">
        <h3 className="text-[10px] font-bold text-blue-500 uppercase tracking-[0.3em] mb-6">Phase 0{idx}</h3>
        <h2 className="text-5xl font-bold text-white mb-16 tracking-tight">{pillar.label}</h2>
        <div className="space-y-16">
          {pillar.questions.map((q, qIdx) => (
            <div key={qIdx}>
              <p className="text-2xl text-zinc-300 mb-10 font-light">{q}</p>
              <div className="grid grid-cols-5 gap-4">
                {[1, 2, 3, 4, 5].map((val) => (
                  <button
                    key={val}
                    onClick={() => handleScoreChange(pillar.id, val)}
                    className={`h-20 rounded-2xl border transition-all font-bold text-xl ${
                      scores[pillar.id] === val 
                        ? 'bg-blue-600 border-blue-600 text-white shadow-[0_0_30px_rgba(59,130,246,0.4)] scale-105' 
                        : 'bg-white/5 border-white/5 text-zinc-600 hover:border-white/10'
                    }`}
                  >
                    {val}
                  </button>
                ))}
              </div>
              <div className="flex justify-between text-[10px] text-zinc-700 mt-6 font-bold uppercase tracking-[0.2em]">
                <span>Underdeveloped</span>
                <span>Highly Strategic</span>
              </div>
            </div>
          ))}
        </div>
        <div className="mt-24 flex justify-between items-center">
           <button onClick={() => setStep(step - 1)} className="text-zinc-600 font-bold hover:text-white transition-colors text-xs uppercase tracking-widest">Previous</button>
           <button 
             disabled={scores[pillar.id] === 0}
             onClick={nextStep} 
             className="px-12 py-5 bg-white text-black font-bold rounded-full hover:bg-zinc-200 disabled:opacity-20 transition-all text-lg shadow-xl"
           >
             Continue
           </button>
        </div>
      </div>
    );
  };

  const renderContactStep = () => (
    <div className="max-w-2xl mx-auto py-12 text-center animate-fade-up">
      <h2 className="text-5xl font-bold text-white mb-10 tracking-tight">Generate Report</h2>
      <p className="text-zinc-400 mb-16 text-xl font-light">Where should I send your strategic gap analysis?</p>
      <div className="space-y-6 mb-16">
        <input 
          type="text" 
          placeholder="Name" 
          className="w-full bg-white/5 border border-white/10 p-6 rounded-2xl text-white text-lg outline-none focus:border-blue-600 transition-colors placeholder:text-zinc-700"
          value={userInfo.name}
          onChange={e => setUserInfo({...userInfo, name: e.target.value})}
        />
        <input 
          type="email" 
          placeholder="Business Email" 
          className="w-full bg-white/5 border border-white/10 p-6 rounded-2xl text-white text-lg outline-none focus:border-blue-600 transition-colors placeholder:text-zinc-700"
          value={userInfo.email}
          onChange={e => setUserInfo({...userInfo, email: e.target.value})}
        />
        <input 
          type="text" 
          placeholder="Organization" 
          className="w-full bg-white/5 border border-white/10 p-6 rounded-2xl text-white text-lg outline-none focus:border-blue-600 transition-colors placeholder:text-zinc-700"
          value={userInfo.company}
          onChange={e => setUserInfo({...userInfo, company: e.target.value})}
        />
      </div>
      <button 
        disabled={!userInfo.name || !userInfo.email}
        onClick={nextStep}
        className="w-full py-6 bg-blue-600 text-white font-bold rounded-full hover:bg-blue-500 transition-all text-xl shadow-[0_0_50px_rgba(59,130,246,0.3)]"
      >
        Complete Diagnosis
      </button>
    </div>
  );

  const renderResults = () => {
    const avg = (Object.values(scores) as number[]).reduce((a, b) => a + b, 0) / 5;
    const level = Math.ceil(avg);
    const insights = [
      { pillar: 'Strategy', status: scores.strategy > 3 ? 'High' : 'Critical' },
      { pillar: 'Operations', status: scores.operations > 3 ? 'Efficient' : 'Manual' },
      { pillar: 'Data', status: scores.data > 3 ? 'Ready' : 'Fragmented' },
    ];

    return (
      <div className="max-w-5xl mx-auto py-24 animate-fade-up">
        <div className="text-center mb-24">
          <h2 className="text-[10px] font-bold text-zinc-600 mb-6 uppercase tracking-[0.3em]">AI Foundation Score</h2>
          <div className="text-[10rem] font-black text-white mb-10 leading-none tracking-tighter glow-blue">
            {avg.toFixed(1)}<span className="text-blue-600 text-6xl">/5</span>
          </div>
          <p className="text-3xl text-white font-bold tracking-tight">
            {level <= 2 ? 'Stage 1: Observational' : level <= 4 ? 'Stage 3: Integrated' : 'Stage 5: Autonomous'}
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-24">
          {insights.map((insight, i) => (
            <div key={i} className="glass-card p-10 rounded-[2.5rem] border-white/5 hover:border-blue-600/30 transition-all">
               <h4 className="text-zinc-600 text-[10px] font-bold uppercase mb-4 tracking-widest">{insight.pillar} Status</h4>
               <p className={`text-2xl font-bold tracking-tight ${insight.status === 'High' || insight.status === 'Efficient' || insight.status === 'Ready' ? 'text-blue-500' : 'text-zinc-400'}`}>
                 {insight.status}
               </p>
            </div>
          ))}
        </div>

        <div className="bg-blue-600 rounded-[4rem] p-20 text-center text-white relative overflow-hidden group">
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-br from-white/10 to-transparent pointer-events-none" />
          <h3 className="text-4xl md:text-5xl font-bold mb-10 tracking-tight">Next Step: 15-Page Blueprint</h3>
          <p className="text-xl text-blue-100 mb-16 max-w-2xl mx-auto font-light leading-relaxed">
            I've processed your organizational profile. You'll receive a detailed roadmap and competitive gap analysis via email within 24 hours.
          </p>
          <a href="#home" className="inline-block px-14 py-7 bg-white text-black font-bold rounded-full hover:bg-zinc-100 transition-all text-xl hover:scale-105 active:scale-95 shadow-2xl">
            Return to HQ
          </a>
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-[#080808] pt-12 px-6">
      <div className="max-w-6xl mx-auto">
        {step > 0 && step <= PILLARS.length + 1 && renderProgress()}
        {step === 0 && renderIntro()}
        {step >= 1 && step <= PILLARS.length && renderPillarStep(step)}
        {step === PILLARS.length + 1 && renderContactStep()}
        {step === PILLARS.length + 2 && renderResults()}
      </div>
    </div>
  );
};

